export type Cell = [row: number, col: number];

const key = (cell: Cell): string => `${cell[0]},${cell[1]}`;

const neighbors = (cell: Cell): Cell[] => {
  const [r, c] = cell;
  return [
    [r - 1, c - 1], [r - 1, c], [r - 1, c + 1],
    [r,     c - 1],             [r,     c + 1],
    [r + 1, c - 1], [r + 1, c], [r + 1, c + 1],
  ] as Cell[];
};

export function nextGeneration(cells: Cell[]): Cell[] {
  const liveSet = new Set(cells.map(key));
  const neighborCount = new Map<string, number>();

  for (const cell of cells) {
    for (const n of neighbors(cell)) {
      const k = key(n);
      neighborCount.set(k, (neighborCount.get(k) ?? 0) + 1);
    }
  }

  const result: Cell[] = [];
  for (const [k, count] of neighborCount) {
    const [r, c] = k.split(",").map(Number);
    const cell: Cell = [r, c];
    if (count === 3 || (count === 2 && liveSet.has(k))) {
      result.push(cell);
    }
  }

  result.sort((a, b) => a[0] - b[0] || a[1] - b[1]);
  return result;
}
